import{_ as s,c as a,o as e,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"使用 mystatus: 斜線指令與自然語言查詢 | opencode-mystatus","description":"學習 opencode-mystatus 的兩種查詢方式：斜線指令 /mystatus 和自然語言提問，如何快速查看多個 AI 平台的額度使用情況。","frontmatter":{"title":"使用 mystatus: 斜線指令與自然語言查詢 | opencode-mystatus","sidebarTitle":"使用方法","subtitle":"使用 mystatus：斜線指令和自然語言","description":"學習 opencode-mystatus 的兩種查詢方式：斜線指令 /mystatus 和自然語言提問，如何快速查看多個 AI 平台的額度使用情況。","tags":["快速開始","斜線指令","自然語言"],"prerequisite":["start-quick-start"],"order":2},"headers":[],"relativePath":"zh-tw/vbgate/opencode-mystatus/start/using-mystatus/index.md","filePath":"zh-tw/vbgate/opencode-mystatus/start/using-mystatus/index.md"}'),i={name:"zh-tw/vbgate/opencode-mystatus/start/using-mystatus/index.md"};function o(l,t,p,d,r,h){return e(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="使用-mystatus-斜線指令和自然語言" tabindex="-1">使用 mystatus：斜線指令和自然語言 <a class="header-anchor" href="#使用-mystatus-斜線指令和自然語言" aria-label="Permalink to &quot;使用 mystatus：斜線指令和自然語言&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>使用 <code>/mystatus</code> 斜線指令一鍵查詢所有 AI 平台額度</li><li>用自然語言提問讓 OpenCode 自動呼叫 mystatus 工具</li><li>理解斜線指令和自然語言兩種觸發方式的區別和適用場景</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你在使用多個 AI 平台開發（OpenAI、智證 AI、GitHub Copilot 等），想知道每個平台還剩多少額度，但不想逐個登入各平台查看——太麻煩了。</p><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li><strong>需要快速查看所有平台額度時</strong>：每天開發前檢查一下，合理安排使用</li><li><strong>想知道某個平台具體額度時</strong>：比如想確認 OpenAI 是否快用完了</li><li><strong>想檢查配置是否生效時</strong>：剛配置好新帳號，驗證一下能否正常查詢</li></ul><div class="info custom-block"><p class="custom-block-title">前置檢查</p><p>本教學假設你已完成<a href="/docs/opencodedocs/zh-tw/vbgate/opencode-mystatus/start/quick-start/">opencode-mystatus 外掛安裝</a>。如果還沒有安裝，請先完成安裝步驟。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>opencode-mystatus 提供了兩種觸發 mystatus 工具的方式：</p><ol><li><strong>斜線指令 <code>/mystatus</code></strong>：快速、直接、無歧義，適合頻繁查詢</li><li><strong>自然語言提問</strong>：更靈活，適合結合具體場景的查詢</li></ol><p>兩種方式都會呼叫同一個 <code>mystatus</code> 工具，工具會並行查詢所有已配置的 AI 平台額度，返回帶進度條、使用統計和重置倒數計時的結果。</p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-使用斜線指令查詢額度" tabindex="-1">第 1 步：使用斜線指令查詢額度 <a class="header-anchor" href="#第-1-步-使用斜線指令查詢額度" aria-label="Permalink to &quot;第 1 步：使用斜線指令查詢額度&quot;">​</a></h3><p>在 OpenCode 中輸入以下指令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>為什麼</strong> 斜線指令是 OpenCode 的快捷指令機制，可以快速呼叫預定義的工具。<code>/mystatus</code> 指令會直接呼叫 mystatus 工具，無需額外參數。</p><p><strong>你應該看到</strong>： OpenCode 會返回所有已配置平台的額度資訊，格式如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI 帳號額度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (team)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3小時限額</span></span>
<span class="line"><span>███████████████████████████ 剩餘 85%</span></span>
<span class="line"><span>重置: 2h 30m後</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 智證 AI 帳號額度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        9c89****AQVM (Coding Plan)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5小時 token 限額</span></span>
<span class="line"><span>███████████████████████████ 剩餘 95%</span></span>
<span class="line"><span>已用: 0.5M / 10.0M</span></span>
<span class="line"><span>重置: 4h後</span></span></code></pre></div><p>每個平台會顯示：</p><ul><li>帳號資訊（郵件或脫敏後的 API Key）</li><li>進度條（可視化顯示剩餘額度）</li><li>重置時間倒數計時</li><li>已用量和總量（部分平台）</li></ul><h3 id="第-2-步-用自然語言提問" tabindex="-1">第 2 步：用自然語言提問 <a class="header-anchor" href="#第-2-步-用自然語言提問" aria-label="Permalink to &quot;第 2 步：用自然語言提問&quot;">​</a></h3><p>除了斜線指令，你也可以用自然語言提問，OpenCode 會自動識別意圖並呼叫 mystatus 工具。</p><p>試試這些提問方式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenAI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span></span></code></pre></div><p>或</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">How</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> much</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> have</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> left?</span></span></code></pre></div><p>或</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p><strong>為什麼</strong> 自然語言查詢更符合日常對話習慣，適合在具體開發場景中提出問題。OpenCode 會透過語意匹配識別出你想查詢額度，並自動呼叫 mystatus 工具。</p><p><strong>你應該看到</strong>： 與斜線指令相同的輸出結果，只是觸發方式不同。</p><h3 id="第-3-步-理解斜線指令的配置" tabindex="-1">第 3 步：理解斜線指令的配置 <a class="header-anchor" href="#第-3-步-理解斜線指令的配置" aria-label="Permalink to &quot;第 3 步：理解斜線指令的配置&quot;">​</a></h3><p>斜線指令 <code>/mystatus</code> 是如何工作的？它是在 OpenCode 配置檔中定義的。</p><p>開啟 <code>~/.config/opencode/opencode.json</code>，找到 <code>command</code> 部分：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opencode-mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Query quota usage for all AI accounts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;template&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Use mystatus tool to query quota usage. Return result as-is without modification.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>關鍵配置項說明</strong>：</p><table tabindex="0"><thead><tr><th>配置項</th><th>值</th><th>作用</th></tr></thead><tbody><tr><td><code>description</code></td><td>&quot;Query quota usage for all AI accounts&quot;</td><td>在指令清單中顯示的說明</td></tr><tr><td><code>template</code></td><td>&quot;Use to mystatus tool...&quot;</td><td>提示 OpenCode 如何處理這個指令</td></tr></tbody></table><p><strong>為什麼需要 template</strong> template 是給 OpenCode 的&quot;指令&quot;，告訴它：當使用者輸入 <code>/mystatus</code> 時，呼叫 mystatus 工具，並將結果原樣返回給使用者（不做任何修改）。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><p>確認你已經掌握了兩種使用方式：</p><table tabindex="0"><thead><tr><th>技能</th><th>檢查方法</th><th>預期結果</th></tr></thead><tbody><tr><td>斜線指令查詢</td><td>輸入 <code>/mystatus</code></td><td>顯示所有平台的額度資訊</td></tr><tr><td>自然語言查詢</td><td>輸入 &quot;Check my OpenAI quota&quot;</td><td>顯示額度資訊</td></tr><tr><td>理解配置</td><td>查看 opencode.json</td><td>找到 mystatus 指令配置</td></tr></tbody></table><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="常見錯誤-1-斜線指令無回應" tabindex="-1">常見錯誤 1：斜線指令無回應 <a class="header-anchor" href="#常見錯誤-1-斜線指令無回應" aria-label="Permalink to &quot;常見錯誤 1：斜線指令無回應&quot;">​</a></h3><p><strong>現象</strong>：輸入 <code>/mystatus</code> 後沒有任何反應</p><p><strong>原因</strong>：OpenCode 配置檔沒有正確配置斜線指令</p><p><strong>解決方法</strong>：</p><ol><li>開啟 <code>~/.config/opencode/opencode.json</code></li><li>確認 <code>command</code> 部分包含 <code>mystatus</code> 配置（見第 3 步）</li><li>重新啟動 OpenCode</li></ol><h3 id="常見錯誤-2-自然語言提問沒有呼叫-mystatus-工具" tabindex="-1">常見錯誤 2：自然語言提問沒有呼叫 mystatus 工具 <a class="header-anchor" href="#常見錯誤-2-自然語言提問沒有呼叫-mystatus-工具" aria-label="Permalink to &quot;常見錯誤 2：自然語言提問沒有呼叫 mystatus 工具&quot;">​</a></h3><p><strong>現象</strong>：輸入 &quot;Check my OpenAI quota&quot; 後，OpenCode 沒有呼叫 mystatus 工具，而是嘗試自己回答</p><p><strong>原因</strong>：OpenCode 沒有正確識別你的意圖</p><p><strong>解決方法</strong>：</p><ol><li>嘗試更明確的表達：&quot;Use mystatus tool to check my OpenAI quota&quot;</li><li>或直接使用斜線指令 <code>/mystatus</code>，更可靠</li></ol><h3 id="常見錯誤-3-顯示-未找到任何已配置的帳號" tabindex="-1">常見錯誤 3：顯示&quot;未找到任何已配置的帳號&quot; <a class="header-anchor" href="#常見錯誤-3-顯示-未找到任何已配置的帳號" aria-label="Permalink to &quot;常見錯誤 3：顯示&quot;未找到任何已配置的帳號&quot;&quot;">​</a></h3><p><strong>現象</strong>：執行 <code>/mystatus</code> 後顯示&quot;未找到任何已配置的帳號&quot;</p><p><strong>原因</strong>：還沒有配置任何平台的認證資訊</p><p><strong>解決方法</strong>：</p><ul><li>至少配置一個平台的認證資訊（OpenAI、智證 AI、Z.ai、GitHub Copilot 或 Google Cloud）</li><li>詳見 <a href="/docs/opencodedocs/zh-tw/vbgate/opencode-mystatus/start/quick-start/">快速開始教學</a> 中的配置說明</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>mystatus 工具提供了兩種使用方式：</p><ol><li><strong>斜線指令 <code>/mystatus</code></strong>：快速直接，適合頻繁查詢</li><li><strong>自然語言提問</strong>：更靈活，適合結合具體場景</li></ol><p>兩種方式都會並行查詢所有已配置的 AI 平台額度，返回帶進度條和重置倒數計時的結果。斜線指令的配置在 <code>~/.config/opencode/opencode.json</code> 中定義，透過 template 指示 OpenCode 如何呼叫 mystatus 工具。</p><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="/docs/opencodedocs/zh-tw/vbgate/opencode-mystatus/start/understanding-output/">解讀輸出：進度條、重置時間和多帳號</a></strong>。</p><p>你會學到：</p><ul><li>如何解讀進度條的含義</li><li>重置時間倒數計時如何計算</li><li>多帳號場景下的輸出格式</li><li>進度條生成原理</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>mystatus 工具定義</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>29-33</td></tr><tr><td>工具描述</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>30-31</td></tr><tr><td>斜線指令配置</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/command/mystatus.md" target="_blank" rel="noreferrer"><code>command/mystatus.md</code></a></td><td>1-6</td></tr><tr><td>並行查詢所有平台</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>49-56</td></tr><tr><td>結果收集和彙總</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>58-89</td></tr></tbody></table><p><strong>關鍵常數</strong>： 無（本節主要介紹呼叫方式，不涉及具體常數）</p><p><strong>關鍵函數</strong>：</p><ul><li><code>mystatus()</code>：mystatus 工具的主函數，讀取認證檔並並行查詢所有平台（<code>plugin/mystatus.ts:29-33</code>）</li><li><code>collectResult()</code>：收集查詢結果到 results 和 errors 陣列（<code>plugin/mystatus.ts:100-116</code>）</li></ul></details>`,66)])])}const g=s(i,[["render",o]]);export{u as __pageData,g as default};
